			}, nil
		}),
	}

	cfgOpts := config.TestLoopConfigOpts{Assignee: "test-worker"}
	rcfg := config.NewTestConfigForLoop(cfgOpts).Resolve(config.TestLoopOverrides(cfgOpts))
	_, err := worker.Run(context.Background(), rcfg, ExecuteBeadLoopRuntime{
